import java.util.*;
public class Raw {
    @SuppressWarnings("unchecked")
    public static void main(String[] args) {
        List numbers = new ArrayList();   // raw type
        numbers.add(42);
        numbers.add("oops");              // String slips in
        List<Integer> ints = numbers;     // unchecked cast
        int first = ints.get(0);          // fine
        int second = ints.get(1);         // ClassCastException here
    }
